import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Erweiterte Nutzung: Tiefere Konfiguration und Optimierung | opencode-notify-Tutorial","description":"Lerne die erweiterte Konfiguration von opencode-notify: Konfigurationsreferenz, Ruhezeiten, Terminalerkennung und Best Practices. Optimiere deine Benachrichtigungserfahrung nach deinen Bedürfnissen und steigere deine Effizienz.","frontmatter":{"title":"Erweiterte Nutzung: Tiefere Konfiguration und Optimierung | opencode-notify-Tutorial","sidebarTitle":"Passe deine Benachrichtigungserfahrung an","subtitle":"Erweiterte Nutzung: Tiefere Konfiguration und Optimierung","description":"Lerne die erweiterte Konfiguration von opencode-notify: Konfigurationsreferenz, Ruhezeiten, Terminalerkennung und Best Practices. Optimiere deine Benachrichtigungserfahrung nach deinen Bedürfnissen und steigere deine Effizienz.","tags":["Erweitert","Konfiguration","Optimierung"],"prerequisite":["/de/kdcokenny/opencode-notify/start/quick-start","/de/kdcokenny/opencode-notify/start/how-it-works"],"order":3},"headers":[],"relativePath":"de/kdcokenny/opencode-notify/advanced/index.md","filePath":"de/kdcokenny/opencode-notify/advanced/index.md"}'),o={name:"de/kdcokenny/opencode-notify/advanced/index.md"};function a(s,e,d,u,l,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="erweiterte-nutzung-tiefere-konfiguration-und-optimierung" tabindex="-1">Erweiterte Nutzung: Tiefere Konfiguration und Optimierung <a class="header-anchor" href="#erweiterte-nutzung-tiefere-konfiguration-und-optimierung" aria-label="Permalink to &quot;Erweiterte Nutzung: Tiefere Konfiguration und Optimierung&quot;">​</a></h1><p>Dieses Kapitel hilft dir, die fortgeschrittenen Funktionen von opencode-notify zu beherrschen, Konfigurationsoptionen zu verstehen, Benachrichtigungserlebnisse zu optimieren und Benachrichtigungsverhalten nach deinen persönlichen Bedürfnissen anzupassen.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Wir empfehlen, dieses Kapitel in der folgenden Reihenfolge zu lernen:</p><h3 id="_1-konfigurationsreferenz" tabindex="-1">1. <a href="./config-reference/">Konfigurationsreferenz</a> <a class="header-anchor" href="#_1-konfigurationsreferenz" aria-label="Permalink to &quot;1. [Konfigurationsreferenz](./config-reference/)&quot;">​</a></h3><p>Verstehe alle verfügbaren Konfigurationsoptionen und ihre Funktionen vollständig.</p><ul><li>Beherrsche die Struktur und Syntax der Konfigurationsdatei</li><li>Lerne Methoden zur Anpassung von Benachrichtigungstönen</li><li>Verstehe die Verwendungsszenarien für die Subsitzungs-Benachrichtigungsumschaltung</li><li>Erfahre die Konfigurationsmethode für Terminaltyp-Overrides</li></ul><h3 id="_2-ruhezeiten-im-detail" tabindex="-1">2. <a href="./quiet-hours/">Ruhezeiten im Detail</a> <a class="header-anchor" href="#_2-ruhezeiten-im-detail" aria-label="Permalink to &quot;2. [Ruhezeiten im Detail](./quiet-hours/)&quot;">​</a></h3><p>Lerne, wie du Ruhezeiten einrichtest, um zu bestimmten Zeiten nicht gestört zu werden.</p><ul><li>Konfiguriere Start- und Endzeiten für Ruhezeiten</li><li>Behandle Ruhezeiten über Nacht (z. B. 22:00 - 08:00)</li><li>Deaktiviere bei Bedarf temporär die Ruhezeitanfunktion</li><li>Verstehe die Priorität von Ruhezeiten im Verhältnis zu anderen Filterregeln</li></ul><h3 id="_3-terminalerkennungs-prinzipien" tabindex="-1">3. <a href="./terminal-detection/">Terminalerkennungs-Prinzipien</a> <a class="header-anchor" href="#_3-terminalerkennungs-prinzipien" aria-label="Permalink to &quot;3. [Terminalerkennungs-Prinzipien](./terminal-detection/)&quot;">​</a></h3><p>Verstehe die Funktionsweise der automatischen Terminalerkennung im Detail.</p><ul><li>Lerne, wie das Plugin 37+ Terminal-Emulatoren erkennt</li><li>Verstehe die Implementierung der Fokuserkennung auf der macOS-Plattform</li><li>Beherrsche Methoden zur manuellen Angabe des Terminaltyps</li><li>Verstehe das Standardverhalten bei Erkennungsfehlern</li></ul><h3 id="_4-erweiterte-nutzung" tabindex="-1">4. <a href="./advanced-usage/">Erweiterte Nutzung</a> <a class="header-anchor" href="#_4-erweiterte-nutzung" aria-label="Permalink to &quot;4. [Erweiterte Nutzung](./advanced-usage/)&quot;">​</a></h3><p>Beherrsche Konfigurationstechniken und Best Practices.</p><ul><li>Konfigurationsstrategien zur Vermeidung von Benachrichtigungs-Spam</li><li>Anpassen des Benachrichtigungsverhaltens an deinen Workflow</li><li>Konfigurationsempfehlungen für Multi-Window- und Multi-Terminal-Umgebungen</li><li>Leistungsoptimierung und Fehlerbehebungstechniken</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie mit diesem Kapitel beginnen, wird empfohlen, die folgenden Grundlagen abzuschließen:</p><ul><li>✅ <strong>Schnellstart</strong>: Installation des Plugins und grundlegende Konfiguration</li><li>✅ <strong>Funktionsweise</strong>: Verständnis der Kernfunktionen des Plugins und des Ereignisüberwachungsmechanismus</li><li>✅ <strong>Plattformfunktionen</strong> (optional): Verständnis der plattformspezifischen Funktionen, die Sie verwenden</li></ul><div class="tip custom-block"><p class="custom-block-title">Lernempfehlung</p><p>Wenn Sie nur Benachrichtigungstöne anpassen oder Ruhezeiten einrichten möchten, können Sie direkt zur entsprechenden Unterseite springen. Bei Problemen können Sie jederzeit das Kapitel Konfigurationsreferenz konsultieren.</p></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie weiter erkunden:</p><ul><li><strong><a href="./../../faq/troubleshooting/">Fehlerbehebung</a></strong>: Lösungen für häufige Probleme und Schwierigkeiten</li><li><strong><a href="./../../faq/common-questions/">Häufig gestellte Fragen</a></strong>: Verständnis wichtiger Fragen, die Nutzer interessieren</li><li><strong><a href="./../../appendix/event-types/">Ereignistyp-Erklärung</a></strong>: Tiefes Erlernen aller Ereignistypen, die das Plugin überwacht</li><li><strong><a href="./../../appendix/config-file-example/">Konfigurationsdatei-Beispiel</a></strong>: Ansehen eines vollständigen Konfigurationsbeispiels mit Kommentaren</li></ul><hr><details><summary><strong>Klicken, um Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeile</th></tr></thead><tbody><tr><td>Konfigurationsschnittstelle-Definition</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr><tr><td>Standardkonfiguration</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L56-L68" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>56-68</td></tr><tr><td>Konfigurationsladung</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>Ruhezeit-Prüfung</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>Terminalerkennung</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>Terminalprozessnamenzuordnung</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L71-L84" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>71-84</td></tr></tbody></table><p><strong>Wichtige Schnittstellen</strong>:</p><ul><li><code>NotifyConfig</code>: Konfigurationsschnittstelle, enthält alle konfigurierbaren Elemente</li><li><code>quietHours</code>: Ruhezeitkonfiguration (enabled/start/end)</li><li><code>sounds</code>: Soundkonfiguration (idle/error/permission)</li><li><code>terminal</code>: Terminaltyp-Override (optional)</li></ul><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>DEFAULT_CONFIG</code>: Standardwerte aller Konfigurationselemente</li><li><code>TERMINAL_PROCESS_NAMES</code>: Zuordnungstabelle von Terminalnamen zu macOS-Prozessnamen</li></ul></details>',25)])])}const f=n(o,[["render",a]]);export{g as __pageData,f as default};
